import React from 'react';
import Clock from './Clock';

function Sidebar({ activePage, setActivePage, isOpen, setIsOpen }) {
  const menuItems = [
    { id: 'home', label: 'Home' },
    { id: 'about', label: 'About Indus' },
    { id: 'programs', label: 'Programs' },
    { id: 'institutes', label: 'Institutes' },
    { id: 'map', label: 'Campus Map' },
    { id: 'events', label: 'Events' },
  ];

  const handleNavigate = (id) => {
    setActivePage(id);
    setIsOpen(false);
  };

  return (
    <>
      <aside 
        className={`fixed inset-y-0 left-0 z-50 w-64 bg-white p-8 flex flex-col justify-between border-r border-gray-200 transition-transform duration-300 md:relative md:translate-x-0 ${
          isOpen ? 'translate-x-0' : '-translate-x-full'
        }`}
      >
        <div>
          <div className="text-3xl font-bold text-gray-900 mb-1">INDUS UNIVERSITY</div>
          <div className="text-sm text-gray-500 mb-10">Where Practice Meets Theory</div>

          <ul className="space-y-2">
            {menuItems.map((item) => (
              <li
                key={item.id}
                className={`p-4 rounded-xl cursor-pointer transition-colors duration-200 font-medium ${
                  activePage === item.id 
                    ? 'bg-[#e8e3df] text-gray-900 shadow-sm' 
                    : 'text-gray-600 hover:bg-gray-50'
                }`}
                onClick={() => handleNavigate(item.id)}
              >
                {item.label}
              </li>
            ))}
          </ul>
        </div>

        <Clock />
      </aside>

      {/* Mobile Overlay */}
      {isOpen && (
        <div 
          className="fixed inset-0 z-40 bg-black/40 backdrop-blur-sm transition-opacity md:hidden" 
          onClick={() => setIsOpen(false)}
        ></div>
      )}
    </>
  );
}

export default Sidebar;
